{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization and search task involving spatial reasoning, uncertainty reduction, and cost minimization. I am breaking it down into geometric modeling, query strategy optimization, and cost estimation.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Define a mathematical representation for the polyomino shapes and the grid. Create a function that calculates the possible valid placements (translations and rotations) of each polyomino shape within the grid boundaries, accounting for potential overlaps or constraints."
    },
    {
      "label": "query_optimizer",
      "instructions": "Develop an information-theoretic approach to select the next probing or aggregate query. Given a set of possible polyomino placements, calculate the expected reduction in entropy (uncertainty) for different query types (drilling vs. noisy aggregate) to minimize the total number of probes required to isolate the oil cells."
    },
    {
      "label": "cost_evaluator",
      "instructions": "Create a cost function that aggregates the expenses of drilling, noisy aggregate queries, and the penalty for incorrect final guesses. This function should be used to evaluate different search strategies and determine the optimal path to minimize the total score."
    }
  ],
  "synthesis_brief": "Combine the geometric placement possibilities from the geometric_modeler with the query selection logic from the query_optimizer. Use the cost_evaluator to weight the trade-offs between high-certainty drilling and low-cost noisy queries to produce the final sequence of actions and the resulting oil-cell coordinates."
}

